// Pull every hotel's user rankings and aggregate them into one leaderboard.
//
// Output: public/data/leaderboard.json — the ONLY thing the site loads.
// It contains just: name, property, HootScore, level. No emails or other PII —
// email is used server-side only to classify Corporate staff, then discarded.
//
// Keys come from the CYBERHOOT_HOTELS env var (used on Netlify) or, if that's
// absent, from config/hotels.json (local dev, generated by `npm run setup`).
//
// Usage: node scripts/fetch-leaderboard.mjs

import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { chGet, mapPool } from './cyberhoot.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');
const CONFIG = resolve(ROOT, 'config', 'hotels.json');
const OUT = resolve(ROOT, 'public', 'data', 'leaderboard.json');

const CONCURRENCY = 5; // be polite; ~70 requests total

// CyberHoot HootRank levels, lowest → highest, for tie-breaking.
const LEVEL_ORDER = ['hatchling', 'novice', 'explorer', 'protector', 'guardian', 'sage'];
const levelIdx = (r) => LEVEL_ORDER.indexOf((r || '').toLowerCase()); // -1 if unknown

// A HootScore is only meaningful when it's a real number >= 0.
// The API uses -1 / 'n/a' to mean "not applicable yet".
function validScore(v) {
  const n = Number(v);
  return Number.isFinite(n) && n >= 0 && v !== 'n/a' && v !== null && v !== '';
}
const num = (v) => (validScore(v) ? Number(v) : null);

// Emails to omit from the board (e.g. program admins). Sourced from the
// CYBERHOOT_EXCLUDE env var (comma-separated) and/or config/exclude.json.
function loadExcludes() {
  const set = new Set();
  const add = (e) => {
    const v = (e || '').trim().toLowerCase();
    if (v) set.add(v);
  };
  (process.env.CYBERHOOT_EXCLUDE || '').split(',').forEach(add);
  try {
    const cfg = JSON.parse(readFileSync(resolve(ROOT, 'config', 'exclude.json'), 'utf8'));
    (cfg.emails || []).forEach(add);
  } catch {
    /* no exclude file — fine */
  }
  return set;
}

function loadHotels() {
  const env = process.env.CYBERHOOT_HOTELS;
  if (env && env.trim()) {
    try {
      const parsed = JSON.parse(env);
      if (Array.isArray(parsed) && parsed.length) return parsed;
      console.error('CYBERHOOT_HOTELS is set but is not a non-empty JSON array.');
      process.exit(1);
    } catch (e) {
      console.error(`CYBERHOOT_HOTELS is not valid JSON: ${e.message}`);
      process.exit(1);
    }
  }
  try {
    return JSON.parse(readFileSync(CONFIG, 'utf8'));
  } catch {
    console.error(`No CYBERHOOT_HOTELS env var and missing ${CONFIG}. Run: npm run setup`);
    process.exit(1);
  }
}

async function fetchHotel(hotel) {
  const status = { code: hotel.code, name: hotel.name, status: 'ok' };
  try {
    // Resolve the customer id (each key auto-scopes to its one hotel).
    const customer = await chGet('/customers', hotel.apiKey);
    const cust = Array.isArray(customer) ? customer[0] : customer;
    const customerId = cust?.id;

    // Per-user HootRank/Score details (object keyed by user_id).
    const path = customerId
      ? `/hoot-ranks/user/user-rankings.php?customer_id=${customerId}`
      : '/hoot-ranks/user/user-rankings.php';
    const ranked = await chGet(path, hotel.apiKey);
    const rows = ranked && typeof ranked === 'object' ? Object.values(ranked) : [];

    const users = rows
      .map((u) => ({
        name: `${(u.first_name || '').trim()} ${(u.last_name || '').trim()}`.trim(),
        property: hotel.name, // the environment this key belongs to
        hootScore: num(u.hoot_score),
        hootRank: (u.hoot_rank || '').trim() || null,
        _email: (u.email_address || '').trim().toLowerCase(), // internal only
        _corp: !!hotel.corporate, // corporate environment wins on dedupe
        // Internal tie-breakers (never written to output): among equal
        // HootScores, reward more training completed, fewer late submissions,
        // and fewer quiz attempts.
        _completed: Number(u.completed_assignments) || 0,
        _late: Number(u.late_submissions) || 0,
        _attempts: Number(u.num_attempts) || 0,
      }))
      .filter((u) => u.name && u.hootScore !== null); // ranked users only

    return { status, users };
  } catch (err) {
    status.status = 'error';
    status.error = err.message || String(err);
    console.error(`  ✗ ${hotel.code} ${hotel.name}: ${status.error}`);
    return { status, users: [] };
  }
}

async function main() {
  const hotels = loadHotels();
  console.log(`Fetching ${hotels.length} hotels (concurrency ${CONCURRENCY})...`);

  const excludes = loadExcludes();
  const results = await mapPool(hotels, CONCURRENCY, fetchHotel);
  let allUsers = results.flatMap((r) => r.users).filter((u) => !excludes.has(u._email));
  if (excludes.size) console.log(`Excluding ${excludes.size} email(s) from the board.`);

  // Dedupe by email (a person can be enrolled in several environments — e.g.
  // corporate staff who also sit in a hotel's environment). Prefer the
  // Corporate environment entry; otherwise keep the highest HootScore. Rows
  // without an email are always kept (can't tell people apart by name alone).
  const preferred = (a, b) => {
    if (a._corp !== b._corp) return a._corp ? a : b;
    return b.hootScore > a.hootScore ? b : a;
  };
  const byEmail = new Map();
  const noEmail = [];
  for (const u of allUsers) {
    if (!u._email) {
      noEmail.push(u);
      continue;
    }
    const existing = byEmail.get(u._email);
    byEmail.set(u._email, existing ? preferred(existing, u) : u);
  }
  allUsers = [...byEmail.values(), ...noEmail];

  // Rank by CyberHoot's HootScore first, then break ties by Level (more
  // experienced owl ranks higher), then by assignment-completion timing — most
  // completed, fewest late, fewest attempts. Every value here is CyberHoot's;
  // this only decides the order among equal HootScores.
  allUsers.sort(
    (a, b) =>
      b.hootScore - a.hootScore ||
      levelIdx(b.hootRank) - levelIdx(a.hootRank) ||
      b._completed - a._completed ||
      a._late - b._late ||
      a._attempts - b._attempts ||
      a.name.localeCompare(b.name)
  );

  const users = allUsers.map((u, i) => ({
    rank: i + 1,
    name: u.name,
    property: u.property,
    hootScore: u.hootScore,
    hootRank: u.hootRank,
  }));

  const hotelSummaries = results.map((r) => r.status);
  const okCount = hotelSummaries.filter((h) => h.status === 'ok').length;
  const payload = {
    generatedAt: new Date().toISOString(),
    hotelCount: hotels.length,
    hotelsOk: okCount,
    userCount: users.length,
    hotels: hotelSummaries,
    users,
  };

  mkdirSync(dirname(OUT), { recursive: true });
  writeFileSync(OUT, JSON.stringify(payload) + '\n');

  console.log(`\nWrote ${users.length} users from ${okCount}/${hotels.length} hotels to ${OUT}`);
  const failed = hotelSummaries.filter((h) => h.status !== 'ok');
  if (failed.length) {
    console.log(`Hotels with errors (${failed.length}): ${failed.map((h) => h.code).join(', ')}`);
    process.exitCode = 2; // surface failures to schedulers, but still wrote what we have
  }
}

main();
